  p_Name_df156de4 := 'ExternalChangeDetection_DetectUpdates';
  p_CategoryID_df156de4 := 'FE1AE5B2-FC57-43B2-B560-A673713E1679';
  p_Description_df156de4 := 'Detects updated records in an external system by comparing UpdatedAt timestamps.';
  p_SQL_df156de4 := '-- T-SQL variant for External Change Detection - Detect Updates
SELECT
    ot.*, ot.[{{ UpdatedAtField }}] AS __ecd_UpdatedAt, rc.last_change_time __ecd_LatestRecordChangeAt
FROM
    [{{ SchemaName }}].[{{ BaseView }}] ot
INNER JOIN (
    SELECT
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM
        __mj.vwRecordChanges
    WHERE
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc."RecordID"
WHERE
    ot.[{{ UpdatedAtField }}] > COALESCE(rc.last_change_time, ''1900-01-01 00:00:00.000'')
ORDER BY
    {{ PrimaryKeyOrderBy }}
';
