-- Save MJ: Query SQLs (core SP call only)
DO $$
DECLARE
  p_QueryID_0e930e55 UUID;
  p_SQLDialectID_0e930e55 UUID;
  p_SQL_0e930e55 TEXT;
  p_ID_0e930e55 UUID;
BEGIN
  p_QueryID_0e930e55 := '3366D42B-C3A1-4CE0-9F40-7FBE15F2EA57';
  p_SQLDialectID_0e930e55 := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_0e930e55 := '-- PostgreSQL variant for External Change Detection - Detect Creations
SELECT
    ot.*, ot."{{ CreatedAtField }}" AS "__ecd_CreatedAt", ot."{{ UpdatedAtField }}" AS "__ecd_UpdatedAt"
FROM
    "{{ SchemaName }}"."{{ BaseView }}" ot
LEFT JOIN
    __mj.vwRecordChanges rc
    ON
    ({{ PrimaryKeyJoin }} = rc."RecordID") AND
    rc."Type" = ''Create'' AND
    rc."EntityID" = {{ EntityID | sqlString }}
WHERE
    rc."RecordID" IS NULL
ORDER BY
    {{ PrimaryKeyOrderBy }}
';
  p_ID_0e930e55 := 'D85DE0AD-5B5B-4EF4-82BC-C634CE39E836';
  PERFORM __mj."spUpdateQuerySQL"(p_QueryID := p_QueryID_0e930e55, p_SQLDialectID := p_SQLDialectID_0e930e55, p_SQL := p_SQL_0e930e55, p_ID := p_ID_0e930e55);
END $$;

-- Save MJ: Query SQLs (core SP call only)
DO $$
DECLARE
  p_QueryID_8f8933eb UUID;
  p_SQLDialectID_8f8933eb UUID;
  p_SQL_8f8933eb TEXT;
  p_ID_8f8933eb UUID;
BEGIN
  p_QueryID_8f8933eb := '46A91235-2122-40E8-9289-20D04489CAC5';
  p_SQLDialectID_8f8933eb := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_8f8933eb := '-- PostgreSQL variant for External Change Detection - Detect Updates
SELECT
    ot.*, ot."{{ UpdatedAtField }}" AS "__ecd_UpdatedAt", rc.last_change_time AS "__ecd_LatestRecordChangeAt"
FROM
    "{{ SchemaName }}"."{{ BaseView }}" ot
INNER JOIN (
    SELECT
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM
        __mj.vwRecordChanges
    WHERE
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc."RecordID"
WHERE
    ot."{{ UpdatedAtField }}" > COALESCE(rc.last_change_time, CAST(''1900-01-01 00:00:00.000'' AS TIMESTAMPTZ))
ORDER BY
    {{ PrimaryKeyOrderBy }}
';
  p_ID_8f8933eb := '565C5AF3-5F59-4531-B21D-53EBC884EF5B';
  PERFORM __mj."spUpdateQuerySQL"(p_QueryID := p_QueryID_8f8933eb, p_SQLDialectID := p_SQLDialectID_8f8933eb, p_SQL := p_SQL_8f8933eb, p_ID := p_ID_8f8933eb);
END $$;

